<?php
namespace App\Controllers;
use App\Core\Auth;use App\Core\Database;use App\Core\View;use App\Services\AuditService;
final class ServiceTerritoryController{public function index():void{Auth::requireRole('owner','office');$rows=Database::connection()->query('SELECT * FROM service_territories ORDER BY active DESC,name')->fetchAll();View::render('portal/territories/index',['title'=>'Service Territories','rows'=>$rows],'portal');}public function store():void{Auth::requireRole('owner','office');verify_csrf();Database::connection()->prepare('INSERT INTO service_territories(name,territory_type,city,state,postal_code,center_lat,center_lng,radius_miles,travel_surcharge,active) VALUES(?,?,?,?,?,?,?,?,?,?)')->execute([trim($_POST['name']),$_POST['territory_type'],($_POST['city']??'')?:null,($_POST['state']??'')?:null,($_POST['postal_code']??'')?:null,($_POST['center_lat']??'')?:null,($_POST['center_lng']??'')?:null,($_POST['radius_miles']??'')?:null,(float)($_POST['travel_surcharge']??0),isset($_POST['active'])?1:0]);flash('success','Service territory saved.');redirect('/portal/territories');}}
